import{_ as n,o as a,c as i,ag as t}from"./chunks/framework.CvgP6Fyv.js";const c=JSON.parse('{"title":"Uitgaven","description":"","frontmatter":{},"headers":[],"relativePath":"nl/features/expenses.md","filePath":"nl/features/expenses.md"}'),r={name:"nl/features/expenses.md"};function o(l,e,s,g,u,d){return a(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="uitgaven" tabindex="-1">Uitgaven <a class="header-anchor" href="#uitgaven" aria-label="Permalink to &quot;Uitgaven&quot;">​</a></h1><p>Houd al je zakelijke uitgaven bij, scan bonnen met AI en categoriseer kosten voor nauwkeurige boekhouding en BTW-aangifte.</p><h2 id="overzicht" tabindex="-1">Overzicht <a class="header-anchor" href="#overzicht" aria-label="Permalink to &quot;Overzicht&quot;">​</a></h2><p>De uitgavenpagina toont al je geregistreerde uitgaven. Filter op:</p><ul><li><strong>Categorie</strong> — Kantoor, reizen, apparatuur, etc.</li><li><strong>Project</strong> — Uitgaven gekoppeld aan specifieke projecten</li><li><strong>Datumbereik</strong> — Filter op uitgavedatum</li><li><strong>Status</strong> — Actief of gearchiveerd</li></ul><h2 id="een-uitgave-aanmaken" tabindex="-1">Een uitgave aanmaken <a class="header-anchor" href="#een-uitgave-aanmaken" aria-label="Permalink to &quot;Een uitgave aanmaken&quot;">​</a></h2><h3 id="handmatige-invoer" tabindex="-1">Handmatige invoer <a class="header-anchor" href="#handmatige-invoer" aria-label="Permalink to &quot;Handmatige invoer&quot;">​</a></h3><ol><li>Ga naar <strong>Uitgaven &gt; Nieuwe uitgave</strong></li><li>Vul in: <ul><li><strong>Omschrijving</strong> — Waarvoor de uitgave is</li><li><strong>Bedrag</strong> — Totale kosten (inclusief of exclusief BTW)</li><li><strong>Datum</strong> — Wanneer de uitgave plaatsvond</li><li><strong>Categorie</strong> — Selecteer uit voorgedefinieerde categorieen</li><li><strong>BTW-tarief</strong> — Toepasselijk BTW-percentage</li></ul></li><li>Voeg optioneel een <strong>bon</strong>-afbeelding of PDF toe</li><li>Koppel optioneel aan een <strong>project</strong> of <strong>klant</strong></li><li>Klik op <strong>Opslaan</strong></li></ol><h3 id="snel-toevoegen" tabindex="-1">Snel toevoegen <a class="header-anchor" href="#snel-toevoegen" aria-label="Permalink to &quot;Snel toevoegen&quot;">​</a></h3><p>Gebruik de snel-toevoegen-lade voor snelle uitgaveninvoer:</p><ol><li>Klik op de snel-toevoegen-knop op de uitgavenlijst</li><li>Vul het bedrag en de omschrijving in</li><li>Selecteer een snelle categorie</li><li>Sla op</li></ol><h3 id="bonnen-scannen" tabindex="-1">Bonnen scannen <a class="header-anchor" href="#bonnen-scannen" aria-label="Permalink to &quot;Bonnen scannen&quot;">​</a></h3><p>Laat AI automatisch uitgavegegevens uit bonnen extraheren:</p><ol><li>Ga naar <strong>Uitgaven &gt; Bon scannen</strong></li><li>Upload een bonafbeelding (JPEG, PNG, WebP) of PDF</li><li>Kies de extractiemodus: <ul><li><strong>Enkel</strong> — Een uitgave van de bon</li><li><strong>Meervoudig</strong> — Meerdere regelitems van een bon</li></ul></li><li>Controleer de geextraheerde gegevens (datum, bedrag, leverancier, omschrijving)</li><li>Bevestig om de uitgave(n) aan te maken</li></ol><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Bonnen scannen vereist het <strong>Pro</strong>-abonnement of hoger.</p></div><h2 id="uitgavecategorieen" tabindex="-1">Uitgavecategorieen <a class="header-anchor" href="#uitgavecategorieen" aria-label="Permalink to &quot;Uitgavecategorieen&quot;">​</a></h2><p>MyCompanyDesk biedt voorgedefinieerde categorieen met iconen voor snelle selectie:</p><ul><li>Kantoorbenodigdheden</li><li>Reizen &amp; vervoer</li><li>Eten &amp; drinken</li><li>Software &amp; abonnementen</li><li>Apparatuur</li><li>Professionele diensten</li><li>Marketing &amp; reclame</li><li>Verzekeringen</li><li>Huur &amp; nutsvoorzieningen</li><li>En meer...</li></ul><p>Categorieen helpen bij het organiseren van je uitgaven en worden gebruikt in rapportages voor kostenspecificaties.</p><h2 id="btw-afhandeling" tabindex="-1">BTW-afhandeling <a class="header-anchor" href="#btw-afhandeling" aria-label="Permalink to &quot;BTW-afhandeling&quot;">​</a></h2><p>Elke uitgave kan een eigen BTW-tarief hebben. Veelgebruikte opties:</p><ul><li><strong>21%</strong> — Standaardtarief</li><li><strong>9%</strong> — Verlaagd tarief</li><li><strong>0%</strong> — Nultarief of vrijgesteld</li></ul><p>Het BTW-bedrag wordt automatisch berekend en opgenomen in je <a href="/nl/features/vat">BTW-rapportages</a>.</p><h2 id="uitgaven-koppelen" tabindex="-1">Uitgaven koppelen <a class="header-anchor" href="#uitgaven-koppelen" aria-label="Permalink to &quot;Uitgaven koppelen&quot;">​</a></h2><p>Koppel uitgaven aan:</p><ul><li><strong>Projecten</strong> — Houd projectkosten nauwkeurig bij</li><li><strong>Klanten</strong> — Koppel kosten aan specifieke klanten</li><li><strong>Leveranciers</strong> — Registreer aan wie je hebt betaald</li></ul><h2 id="bulkacties" tabindex="-1">Bulkacties <a class="header-anchor" href="#bulkacties" aria-label="Permalink to &quot;Bulkacties&quot;">​</a></h2><p>Selecteer meerdere uitgaven voor:</p><ul><li><strong>Categoriseren</strong> — Wijzig categorie in bulk</li><li><strong>Archiveren</strong> — Verplaats naar archief</li><li><strong>Verwijderen</strong> — Permanent verwijderen</li><li><strong>Exporteren</strong> — Download als CSV</li></ul><h2 id="terugkerende-uitgaven" tabindex="-1">Terugkerende uitgaven <a class="header-anchor" href="#terugkerende-uitgaven" aria-label="Permalink to &quot;Terugkerende uitgaven&quot;">​</a></h2><p>Voor regelmatige kosten (huur, abonnementen, etc.) stel je <a href="/nl/features/recurring-expenses">terugkerende uitgaven</a> in om het aanmaken te automatiseren.</p><h2 id="importeren" tabindex="-1">Importeren <a class="header-anchor" href="#importeren" aria-label="Permalink to &quot;Importeren&quot;">​</a></h2><p>Importeer uitgaven vanuit CSV:</p><ol><li>Ga naar <strong>Profiel &gt; Importeren</strong></li><li>Selecteer <strong>Uitgaven</strong> als gegevenstype</li><li>Upload je CSV-bestand</li><li>Koppel kolommen aan velden</li><li>Controleer en bevestig</li></ol><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Schakel <a href="/nl/advanced/ai-features">AI-suggesties</a> in voor automatische categorie-aanbevelingen</li><li>Voeg altijd bonnen toe — ze zijn essentieel voor belastingcontroles</li><li>Gebruik projecten om de verhouding uitgaven-inkomsten bij te houden</li><li>Bekijk het <a href="/nl/features/reports">uitgavenrapport</a> voor bestedingsoverzichten</li></ul>',36)])])}const h=n(r,[["render",o]]);export{c as __pageData,h as default};
